import React, { useContext } from 'react';
import { ModalContext } from '../context/ModalContext';

const CaseStudies = () => {
  const { openCaseStudyModal } = useContext(ModalContext);

  const caseStudies = [
    {
      id: 'andegna-wood-metal',
      image: '/assets/Portfolio/Office Signage For Andegna Furniture.webp',
      category: 'Brand Identity & Logo Design',
      title: 'Andegna Wood & Metal Works',
      description: 'A distinct brand identity for a sister company that stands on its own while feeling connected to the parent brand, communicating strength, craftsmanship, and reliability.'
    },
    {
      id: 'alta-counseling',
      image: '/assets/Portfolio/Full brand identity for Alta Counseling.webp',
      category: 'Brand Identity Redesign',
      title: 'Alta Counseling',
      description: 'A refreshed brand identity that feels calm, trustworthy, and professional while remaining approachable for clients seeking mental health support.'
    },
    {
      id: 'niqat-coffee',
      image: '/assets/Portfolio/Social Media Design for niqat coffee.webp',
      category: 'Social Media Campaign & Brand Presence',
      title: 'Niqat Coffee',
      description: 'Established a strong social media presence from scratch and increased engagement through consistent, visually appealing content that reflects the brand\'s personality.'
    }
  ];

  return (
    <section id="case-studies" className="case-studies" data-aos="fade-up">
      <div className="container">
        <div className="section-intro">
          <span className="section-number">04</span>
          <div className="section-header">
            <span className="section-label">In-Depth Analysis</span>
            <h2 className="section-title">
              <span className="title-main">Case</span>
              <span className="title-accent">Studies</span>
            </h2>
          </div>
        </div>
        
        <div className="case-studies-grid">
          {caseStudies.map((caseStudy) => (
            <article 
              key={caseStudy.id} 
              className="case-study-card" 
              data-project={caseStudy.id}
              onClick={() => openCaseStudyModal(caseStudy.id)}
            >
              <div className="case-study-image">
                <img 
                  src={`${process.env.PUBLIC_URL || ''}${caseStudy.image}`} 
                  alt={`${caseStudy.title} - ${caseStudy.category} case study by Bereket Fikre`} 
                  className="case-study-thumb" 
                  loading="lazy" 
                  width="600" 
                  height="400"
                  decoding="async"
                  sizes="(max-width: 768px) 100vw, (max-width: 1024px) 50vw, 33vw"
                />
                <div className="case-study-overlay"></div>
              </div>
              <div className="case-study-content">
                <span className="case-study-category">{caseStudy.category}</span>
                <h3>{caseStudy.title}</h3>
                <p>{caseStudy.description}</p>
                <a 
                  href="#" 
                  className="case-study-link"
                  onClick={(e) => {
                    e.preventDefault();
                    openCaseStudyModal(caseStudy.id);
                  }}
                  aria-label={`View ${caseStudy.title} case study`}
                >
                  <span>View Case Study</span>
                  <svg width="16" height="16" viewBox="0 0 20 20" fill="none" aria-hidden="true">
                    <path d="M7.5 15L12.5 10L7.5 5" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
                  </svg>
                </a>
              </div>
            </article>
          ))}
        </div>
      </div>
    </section>
  );
};

export default CaseStudies;

